import {
    GridCoreModel
} from "./grid_core";
export class DataGridBaseModel extends GridCoreModel {
    apiColumnOption(id, name, value) {
        const instance = this.getInstance();
        switch (arguments.length) {
            case 1:
                return instance.columnOption(id);
            case 2:
                return instance.columnOption(id, name);
            default:
                instance.columnOption(id, name, value);
                return
        }
    }
    async apiRefresh() {
        await this.getInstance().refresh()
    }
    apiAbortAIColumnRequest(columnName) {
        this.getInstance().abortAIColumnRequest(columnName)
    }
}
